"use strict";exports.id=931,exports.ids=[931],exports.modules={29931:a=>{a.exports=JSON.parse('{"common":{"nav":{"home":"Trang chủ","pricing":"Bảng gi\xe1","contact":"Li\xean hệ","regulations":"Quy định"},"cta":{"freeAssessment":"Khảo s\xe1t miễn ph\xed","getQuote":"Nhận b\xe1o gi\xe1","learnMore":"T\xecm hiểu th\xeam"},"footer":{"tagline":"Điện mặt trời chất lượng Nhật Bản. Lắp đặt đ\xfang chuẩn, tại Việt Nam.","address":"L\xf4 35 đường số 9, KCN Tam Phước, Bi\xean H\xf2a, Việt Nam","markets":"Phục vụ kh\xe1ch h\xe0ng tại Việt Nam v\xe0 c\xe1c đối t\xe1c li\xean kết Nhật Bản tr\xean khắp Đồng Nai, TP. Hồ Ch\xed Minh v\xe0 miền Nam.","privacy":"Ch\xednh s\xe1ch bảo mật","quickLinks":"Li\xean kết nhanh","company":"C\xf4ng ty","contactColumn":"Li\xean hệ","rights":"Đ\xe3 đăng k\xfd bản quyền.","regulations":"Quy định điện mặt trời"},"business":{"addressLabel":"Địa chỉ","phoneLabel":"Điện thoại","emailLabel":"Email","altEmailLabel":"Email phụ","address":"L\xf4 35 đường số 9, KCN Tam Phước, Bi\xean H\xf2a, Đồng Nai, Việt Nam","phone":"+84 90 333 37 29","email":"thuy@tnpgr.vn","altEmail":"anhkiet3333@yahoo.com"},"languages":{"en":"English","vi":"Tiếng Việt","ja":"日本語"}},"home":{"hero":{"title":"Điện mặt trời chất lượng Nhật Bản. Lắp đặt đ\xfang chuẩn, tại Việt Nam.","subtitle":"SolarTNP thiết kế, cung cấp v\xe0 lắp đặt hệ thống điện mặt trời h\xf2a lưới bằng tấm pin năng lượng mặt trời nhập từ Nhật Bản — ph\xf9 hợp với m\xe1i nh\xe0, \xe1nh nắng v\xe0 h\xf3a đơn tiền điện của người Việt.","cta":"Khảo s\xe1t miễn ph\xed","secondaryCta":"Xem c\xf4ng tr\xecnh của ch\xfang t\xf4i","imageAlt":"Tấm pin năng lượng mặt trời lắp tr\xean m\xe1i ng\xf3i dưới bầu trời xanh"},"about":{"title":"C\xf4ng ty Nhật-Việt, x\xe2y dựng từ chất lượng","body":"SolarTNP mang ti\xeau chuẩn nhập h\xe0ng của Nhật Bản v\xe0o thị trường điện mặt trời Việt Nam. Ch\xfang t\xf4i kết hợp tấm pin hiệu suất cao, bảo h\xe0nh d\xe0i hạn từ c\xe1c nh\xe0 sản xuất Nhật Bản uy t\xedn với đội ngũ lắp đặt người Việt am hiểu m\xe1i nh\xe0, kh\xed hậu v\xe0 thực tế lưới điện địa phương. Ch\xfang t\xf4i l\xe0 c\xf4ng ty c\xf2n trẻ — mỗi hệ thống ch\xfang t\xf4i lắp đều được t\xednh to\xe1n đ\xfang v\xe0 thi c\xf4ng kh\xf4ng cắt x\xe9n.","point1":"Tấm pin nhập từ Nhật Bản, bảo h\xe0nh c\xf4ng suất tuyến t\xednh 25 năm","point2":"Đội thi c\xf4ng ri\xeang của ch\xfang t\xf4i — kh\xf4ng thu\xea lại nh\xe0 thầu phụ","point3":"Lo to\xe0n bộ thủ tục h\xf2a lưới với EVN cho kh\xe1ch h\xe0ng","point4":"Hỗ trợ kỹ thuật miễn ph\xed 12 th\xe1ng sau khi lắp đặt"},"process":{"title":"Quy tr\xecnh l\xe0m việc","lead":"Một quy tr\xecnh r\xf5 r\xe0ng gồm ba giai đoạn — từ lần khảo s\xe1t đầu ti\xean đến nhiều năm hỗ trợ sau lắp đặt.","step1":{"title":"Thiết kế & Cung cấp","body":"Ch\xfang t\xf4i bắt đầu bằng khảo s\xe1t hiện trạng v\xe0 đo lượng điện ti\xeau thụ — diện t\xedch m\xe1i, mức ti\xeau thụ điện trung b\xecnh h\xe0ng th\xe1ng, t\xecnh trạng lưới điện. Từ đ\xf3, ch\xfang t\xf4i thiết kế hệ thống đ\xfang c\xf4ng suất v\xe0 cung cấp tấm pin, inverter nhập từ Nhật Bản k\xe8m đầy đủ hồ sơ bảo h\xe0nh."},"step2":{"title":"Lắp đặt","body":"Đội thi c\xf4ng của ch\xfang t\xf4i — kh\xf4ng qua nh\xe0 thầu phụ — đảm nhận to\xe0n bộ việc lắp khung tr\xean m\xe1i, đi d\xe2y, đấu nối inverter, h\xf2a lưới điện v\xe0 vận h\xe0nh thử, sử dụng phụ kiện lắp đặt chuẩn Nhật Bản v\xe0 đi d\xe2y đ\xfang quy chuẩn."},"step3":{"title":"Hỗ trợ sau lắp đặt & Bảo tr\xec","body":"Hệ thống điện mặt trời hoạt động hơn 25 năm. Ch\xfang t\xf4i c\xe0i đặt ứng dụng gi\xe1m s\xe1t ngay trong ng\xe0y lắp đặt, c\xf3 g\xf3i kiểm tra v\xe0 vệ sinh h\xe0ng năm, v\xe0 hỗ trợ kỹ thuật miễn ph\xed trong 12 th\xe1ng đầu."}},"projects":{"title":"C\xf4ng tr\xecnh đ\xe3 thực hiện","lead":"Bốn c\xf4ng tr\xecnh thực tế. C\xf4ng suất thực, vị tr\xed thực, kết quả thực — kh\xf4ng c\xf3 số liệu thổi phồng.","honestNote":"Ch\xfang t\xf4i l\xe0 c\xf4ng ty c\xf2n trẻ. Đ\xe2y l\xe0 bốn c\xf4ng tr\xecnh đầu ti\xean — mỗi c\xf4ng tr\xecnh đều được l\xe0m đ\xfang chuẩn, kh\xf4ng cắt x\xe9n. Nhiều c\xf4ng tr\xecnh kh\xe1c đang được triển khai.","p1":{"title":"Nh\xe0 ri\xeang tại Bi\xean H\xf2a","size":"5 kWp h\xf2a lưới","panels":"16 tấm Panasonic 315W","location":"Nh\xe0 ri\xeang, Bi\xean H\xf2a, Đồng Nai","duration":"Lắp đặt trong 2 ng\xe0y","outcome":"H\xf3a đơn tiền điện giảm từ ~1.800.000 VNĐ xuống c\xf2n ~400.000 VNĐ mỗi th\xe1ng","note":"C\xf4ng tr\xecnh đầu ti\xean của SolarTNP. M\xe1i ng\xf3i Việt Nam — ch\xfang t\xf4i thiết kế khung lắp ri\xeang để giữ nguy\xean khả năng chống thấm.","imageAlt":"Tấm pin năng lượng mặt trời tr\xean m\xe1i ng\xf3i đỏ dưới trời nắng, nh\xe0 ri\xeang Bi\xean H\xf2a"},"p2":{"title":"Nh\xe0 phố tại Thủ Đức","size":"8 kWp h\xf2a lưới","panels":"20 tấm Sharp 400W","location":"Nh\xe0 phố 3 tầng, Thủ Đức, TP. Hồ Ch\xed Minh","duration":"Lắp đặt trong 3 ng\xe0y","outcome":"Sản lượng ~1.040 kWh/th\xe1ng; phần điện dư được b\xe1n l\xean lưới EVN","note":"Kh\xe1ch lo về tải trọng m\xe1i — ch\xfang t\xf4i t\xednh to\xe1n kết cấu trước khi thi c\xf4ng.","imageAlt":"Nh\xe0 phố hiện đại với tấm pin năng lượng mặt trời tr\xean m\xe1i v\xe0 đường ch\xe2n trời TP. Hồ Ch\xed Minh"},"p3":{"title":"Văn ph\xf2ng tại KCN Tam Phước","size":"15 kWp h\xf2a lưới","panels":"30 tấm Kyocera 500W","location":"T\xf2a văn ph\xf2ng, KCN Tam Phước, Bi\xean H\xf2a","duration":"Lắp đặt trong 4 ng\xe0y","outcome":"B\xf9 khoảng 60% điện ti\xeau thụ ban ng\xe0y; thời gian ho\xe0n vốn dự kiến ~5,5 năm","note":"Ch\xfang t\xf4i xử l\xfd to\xe0n bộ thủ tục h\xf2a lưới với EVN — chỉ 3 tuần từ l\xfac nộp hồ sơ đến l\xfac đ\xf3ng điện.","imageAlt":"C\xf4ng nh\xe2n lắp đặt tấm pin năng lượng mặt trời tr\xean m\xe1i nh\xe0 xưởng"},"p4":{"title":"Nh\xe0 d\xe2n tại Long An","size":"6,4 kWp h\xf2a lưới","panels":"16 tấm Sharp 400W","location":"Nh\xe0 ri\xeang, T\xe2n An, Long An","duration":"Lắp đặt trong 2 ng\xe0y","outcome":"Sản lượng ~830 kWh/th\xe1ng; gia đ\xecnh đạt mức tự c\xe2n bằng điện v\xe0o m\xf9a kh\xf4","note":"C\xf4ng tr\xecnh ở tỉnh xa — ch\xfang t\xf4i phối hợp với điện lực địa phương để xin h\xf2a lưới.","imageAlt":"Tấm pin năng lượng mặt trời tr\xean m\xe1i nh\xe0 n\xf4ng th\xf4n với l\xe1 cờ Việt Nam ph\xeda sau"}},"japanese":{"title":"V\xec sao chất lượng Nhật Bản quan trọng","body":"Thị trường điện mặt trời Việt Nam ph\xe1t triển rất nhanh trong những năm gần đ\xe2y — v\xe0 chất lượng kh\xf4ng đồng đều từ c\xe1c nh\xe0 cung cấp gi\xe1 rẻ l\xe0 vấn đề thực sự. Tấm pin Nhật Bản c\xf3 bảo h\xe0nh c\xf4ng suất tuyến t\xednh 25 năm, suy giảm hiệu suất chỉ khoảng 0,45%/năm. C\xe1c tấm pin gi\xe1 rẻ thường suy giảm 1,5–2%/năm, mất một nửa c\xf4ng suất chỉ sau 15 năm. Trong v\xf2ng đời 25 năm của hệ thống, khoảng c\xe1ch n\xe0y gần như lu\xf4n vượt qua ch\xeanh lệch gi\xe1 ban đầu.","point1":"Suy giảm hiệu suất ≤0,45%/năm — vẫn đạt ≥89% c\xf4ng suất danh định ở năm thứ 25","point2":"Sai số sản xuất chặt chẽ hơn v\xe0 kiểm so\xe1t chất lượng nghi\xeam ngặt","point3":"Thời hạn bảo h\xe0nh d\xe0i v\xe0 được tu\xe2n thủ nghi\xeam t\xfac từ c\xe1c nh\xe0 sản xuất uy t\xedn","imageAlt":"Biểu đồ so s\xe1nh suy giảm c\xf4ng suất 25 năm giữa tấm pin th\xf4ng thường v\xe0 tấm pin Nhật Bản"},"cta":{"title":"Sẵn s\xe0ng khảo s\xe1t miễn ph\xed?","body":"Cho ch\xfang t\xf4i biết về m\xe1i nh\xe0 v\xe0 h\xf3a đơn tiền điện của bạn. Ch\xfang t\xf4i sẽ t\xednh to\xe1n hệ thống ph\xf9 hợp — kh\xf4ng \xe1p lực, kh\xf4ng hứa hẹn thổi phồng.","button":"Khảo s\xe1t miễn ph\xed"}},"pricing":{"hero":{"title":"Bảng gi\xe1 & Thời gian ho\xe0n vốn","subtitle":"Ba mức c\xf4ng suất, hạng mục r\xf5 r\xe0ng, v\xe0 c\xe1i nh\xecn trung thực về thời gian ho\xe0n vốn — t\xednh theo m\xe1i nh\xe0 thực tế, kh\xf4ng b\xe1n qu\xe1 c\xf4ng suất cần thiết."},"tiers":{"small":{"name":"Nhỏ","tagline":"Căn hộ & nh\xe0 nhỏ","size":"3–5 kWp","description":"Ph\xf9 hợp với mức ti\xeau thụ ban ng\xe0y của hộ gia đ\xecnh nhỏ — thường từ 4–10 tấm pin t\xf9y diện t\xedch m\xe1i v\xe0 c\xf4ng suất tấm.","price":"Từ X.XXX USD / XXX triệu VNĐ — CẦN BỔ SUNG: chủ doanh nghiệp điền khoảng gi\xe1"},"medium":{"name":"Trung b\xecnh","tagline":"Nh\xe0 gia đ\xecnh & văn ph\xf2ng nhỏ","size":"6–10 kWp","description":"Mức c\xf4ng suất phổ biến nhất trong c\xe1c c\xf4ng tr\xecnh của ch\xfang t\xf4i hiện nay — đ\xe1p ứng phần lớn ti\xeau thụ ban ng\xe0y của một gia đ\xecnh.","price":"Từ X.XXX USD / XXX triệu VNĐ — CẦN BỔ SUNG: chủ doanh nghiệp điền khoảng gi\xe1"},"large":{"name":"Lớn","tagline":"Doanh nghiệp & nh\xe0 xưởng nhỏ","size":"11–20 kWp","description":"D\xe0nh cho văn ph\xf2ng, xưởng sản xuất v\xe0 nh\xe0 m\xe1y nhỏ c\xf3 mức ti\xeau thụ ban ng\xe0y cao hơn v\xe0 diện t\xedch m\xe1i lớn hơn.","price":"B\xe1o gi\xe1 ri\xeang — li\xean hệ với ch\xfang t\xf4i"}},"included":{"title":"Tất cả c\xe1c mức đều bao gồm","items":["Tấm pin v\xe0 inverter nhập từ Nhật Bản k\xe8m đầy đủ hồ sơ bảo h\xe0nh","Khảo s\xe1t hiện trạng, đo lượng điện ti\xeau thụ v\xe0 kiểm tra kết cấu chịu lực","Thi c\xf4ng bởi đội ngũ ri\xeang của ch\xfang t\xf4i — kh\xf4ng qua nh\xe0 thầu phụ","Lo to\xe0n bộ thủ tục h\xf2a lưới EVN v\xe0 th\xf4ng b\xe1o DOIT","C\xe0i đặt v\xe0 hướng dẫn sử dụng ứng dụng gi\xe1m s\xe1t ngay trong ng\xe0y lắp đặt","Hỗ trợ kỹ thuật miễn ph\xed 12 th\xe1ng sau lắp đặt"]},"payback":{"title":"Thời gian ho\xe0n vốn dự kiến","note":"Số liệu dưới đ\xe2y l\xe0 ước t\xednh dựa tr\xean c\xf4ng suất hệ thống điển h\xecnh v\xe0 giả định sản lượng hiện tại. Mức tiết kiệm thực tế phụ thuộc v\xe0o tải ti\xeau thụ của gia đ\xecnh bạn, hướng m\xe1i v\xe0 gi\xe1 điện EVN tại thời điểm lắp đặt. H\xe3y hỏi ch\xfang t\xf4i để c\xf3 con số t\xednh ri\xeang cho h\xf3a đơn của bạn.","table":{"system":"C\xf4ng suất hệ thống","savings":"Tiết kiệm ước t\xednh/th\xe1ng","cost":"Chi ph\xed hệ thống","payback":"Thời gian ho\xe0n vốn ước t\xednh","todo":"CẦN BỔ SUNG — chủ doanh nghiệp x\xe1c nhận","perMonth":"/th\xe1ng"}},"faq":{"title":"C\xe2u hỏi thường gặp","q1":{"question":"Theo quy định hiện h\xe0nh của Việt Nam, t\xf4i được b\xe1n bao nhi\xeau điện dư cho EVN?","answer":"Theo Nghị định 135/2024/NĐ-CP (c\xf3 hiệu lực từ 2024), lượng điện dư b\xe1n l\xean lưới EVN bị giới hạn tối đa 20% c\xf4ng suất lắp đặt của hệ thống. Mục đ\xedch ch\xednh của hệ thống phải l\xe0 tự sử dụng. Phần điện dư được thanh to\xe1n theo gi\xe1 thị trường điện b\xecnh qu\xe2n của năm trước — kh\xf4ng c\xf2n \xe1p dụng gi\xe1 FIT cao như trước đ\xe2y. Với hầu hết kh\xe1ch h\xe0ng d\xe2n dụng, điều n\xe0y c\xf3 nghĩa l\xe0 hiệu quả t\xe0i ch\xednh của điện mặt trời chủ yếu đến từ tiết kiệm tiền điện tự d\xf9ng, kh\xf4ng phải từ doanh thu b\xe1n điện dư. SolarTNP t\xednh to\xe1n c\xf4ng suất hệ thống theo đ\xfang tải ti\xeau thụ thực tế của bạn để tối đa h\xf3a phần tự d\xf9ng v\xe0 giảm thiểu phần điện dư chạm mức giới hạn 20%."},"q2":{"question":"T\xf4i c\xf3 cần xin ph\xe9p hay giấy tờ trước khi lắp đặt kh\xf4ng?","answer":"C\xf3. Với hệ thống dưới 100 kW (gồm hầu hết hộ d\xe2n v\xe0 doanh nghiệp nhỏ), bạn cần nộp th\xf4ng b\xe1o đơn giản tới Sở C\xf4ng Thương (DOIT) cấp tỉnh — kh\xf4ng cần ph\xea duyệt đầu tư đầy đủ. Với hệ thống từ 100 kW–1.000 kW, \xe1p dụng quy tr\xecnh cấp ph\xe9p th\xf4ng thường với ch\xednh quyền địa phương. Với hệ thống tr\xean 1.000 kW b\xe1n điện dư l\xean lưới, cần c\xf3 giấy chứng nhận đăng k\xfd đầu tư v\xe0 Giấy ph\xe9p hoạt động điện lực. SolarTNP thực hiện th\xf4ng b\xe1o DOIT v\xe0 to\xe0n bộ thủ tục h\xf2a lưới EVN cho hệ thống dưới 100 kW — thời gian thường từ 3–6 tuần kể từ khi nộp hồ sơ đến khi đ\xf3ng điện."},"q3":{"question":"Nh\xe0 t\xf4i c\xf3 cần đ\xe1p ứng y\xeau cầu g\xec kh\xe1c kh\xf4ng?","answer":"C\xf3. Theo Nghị định 135/2024/NĐ-CP, hệ thống phải được lắp tr\xean c\xf4ng tr\xecnh tu\xe2n thủ đầy đủ ph\xe1p luật x\xe2y dựng, quyền sử dụng đất, an to\xe0n ph\xf2ng ch\xe1y chữa ch\xe1y v\xe0 quy định về m\xf4i trường. SolarTNP kiểm tra sự tu\xe2n thủ n\xe0y trong buổi khảo s\xe1t miễn ph\xed. Ch\xfang t\xf4i sẽ kh\xf4ng thi c\xf4ng tr\xean c\xf4ng tr\xecnh c\xf2n vướng vấn đề ph\xe1p l\xfd chưa giải quyết — điều n\xe0y bảo vệ bạn cũng như bảo vệ ch\xfang t\xf4i."},"q4":{"question":"Tấm pin c\xf3 chịu được b\xe3o kh\xf4ng?","answer":"Hệ khung lắp của ch\xfang t\xf4i được t\xednh to\xe1n chịu tải gi\xf3 vượt mức tối thiểu của quy chuẩn x\xe2y dựng Việt Nam. Ch\xfang t\xf4i d\xf9ng nh\xf4m ray chuẩn Nhật Bản v\xe0 bu l\xf4ng inox, bắt chắc v\xe0o kết cấu m\xe1i — kh\xf4ng chỉ b\xe1m tr\xean lớp vật liệu bề mặt. Mỗi c\xf4ng tr\xecnh đều c\xf3 t\xednh to\xe1n tải trọng ri\xeang. Ch\xfang t\xf4i thiết kế d\xe0nh ri\xeang cho kh\xed hậu Việt Nam."},"q5":{"question":"Loại m\xe1i n\xe0o lắp được?","answer":"Ch\xfang t\xf4i lắp được tr\xean m\xe1i b\xea t\xf4ng phẳng, m\xe1i ng\xf3i Việt Nam, m\xe1i t\xf4n, v\xe0 m\xe1i composite hoặc tấm sợi xi măng. Mỗi loại m\xe1i d\xf9ng phương ph\xe1p lắp kh\xe1c nhau. Ch\xfang t\xf4i x\xe1c nhận khả năng lắp đặt ngay trong buổi khảo s\xe1t — kh\xf4ng thi c\xf4ng nếu m\xe1i kh\xf4ng ph\xf9 hợp."},"q6":{"question":"V\xec sao chọn tấm pin Nhật Bản thay v\xec h\xe0ng gi\xe1 rẻ?","answer":"Tấm pin Nhật Bản (Panasonic, Sharp, Kyocera) c\xf3 bảo h\xe0nh c\xf4ng suất tuyến t\xednh 25 năm với mức suy giảm ≤0,45%/năm. Đến năm thứ 25, tấm pin vẫn đạt tối thiểu 89% c\xf4ng suất danh định. Tấm pin gi\xe1 rẻ thường suy giảm 1,5–2%/năm — mất một nửa c\xf4ng suất chỉ sau 15 năm. Trong 25 năm, khoảng c\xe1ch hiệu suất n\xe0y gần như lu\xf4n vượt qua phần ch\xeanh lệch gi\xe1 ban đầu. Ch\xfang t\xf4i cung cấp số liệu so s\xe1nh suy giảm c\xf4ng suất cho mọi kh\xe1ch h\xe0ng để bạn tự t\xednh to\xe1n."},"q7":{"question":"Hệ thống điện mặt trời cần bảo tr\xec g\xec?","answer":"Rất \xedt. Vệ sinh tấm pin 2–4 lần/năm (bụi, ph\xe2n chim). Kiểm tra chuy\xean nghiệp h\xe0ng năm: c\xe1c điểm kết nối, độ siết của khung, t\xecnh trạng inverter. SolarTNP c\xf3 g\xf3i bảo tr\xec h\xe0ng năm. Trong 12 th\xe1ng đầu sau lắp đặt, mọi lần gọi hỗ trợ đều miễn ph\xed."},"q8":{"question":"C\xf3 lắp đặt ngo\xe0i khu vực Bi\xean H\xf2a v\xe0 TP. Hồ Ch\xed Minh kh\xf4ng?","answer":"C\xf3, trong phạm vi miền Nam. Ch\xfang t\xf4i đ\xe3 thi c\xf4ng tại Đồng Nai v\xe0 Long An. Ch\xfang t\xf4i đ\xe1nh gi\xe1 từng địa điểm xa theo từng trường hợp cụ thể — chi ph\xed đi lại v\xe0 lưu tr\xfa sẽ được b\xe1o gi\xe1 ri\xeang cho c\xe1c tỉnh xa."}}},"contact":{"hero":{"title":"Đăng k\xfd khảo s\xe1t miễn ph\xed","subtitle":"Cho ch\xfang t\xf4i biết về m\xe1i nh\xe0 v\xe0 h\xf3a đơn tiền điện của bạn. Kh\xf4ng \xe1p lực — chỉ l\xe0 một g\xf3c nh\xecn trung thực về những g\xec c\xf3 thể l\xe0m được."},"form":{"name":{"label":"Họ v\xe0 t\xean"},"email":{"label":"Email"},"phone":{"label":"Số điện thoại / Zalo / WhatsApp","hint":"Ch\xfang t\xf4i sẽ li\xean hệ qua Zalo hoặc WhatsApp"},"propertyType":{"label":"Loại c\xf4ng tr\xecnh","options":["Nh\xe0 / Biệt thự","Nh\xe0 phố / Nh\xe0 mặt tiền","Căn hộ","Văn ph\xf2ng / Thương mại","Nh\xe0 m\xe1y / Nh\xe0 xưởng","Kh\xe1c"]},"roofArea":{"label":"Diện t\xedch m\xe1i ước t\xednh","hint":"V\xed dụ: 60m\xb2 hoặc \\"chưa r\xf5\\""},"province":{"label":"Tỉnh / Th\xe0nh phố","hint":"V\xed dụ: Bi\xean H\xf2a, Thủ Đức, Long An"},"monthlyBill":{"label":"H\xf3a đơn tiền điện h\xe0ng th\xe1ng","hint":"Gi\xfap ch\xfang t\xf4i t\xednh to\xe1n c\xf4ng suất ph\xf9 hợp","options":["Dưới 500.000 VNĐ","500.000–1.000.000 VNĐ","1.000.000–2.000.000 VNĐ","Tr\xean 2.000.000 VNĐ","Chưa r\xf5"]},"language":{"label":"Ng\xf4n ngữ li\xean hệ ưu ti\xean","options":["English","Tiếng Việt","日本語"]},"notes":{"label":"Ghi ch\xfa / c\xe2u hỏi"},"submit":"Đăng k\xfd khảo s\xe1t miễn ph\xed","privacy":"Khi gửi, bạn đồng \xfd với Ch\xednh s\xe1ch bảo mật của ch\xfang t\xf4i. Th\xf4ng tin của bạn chỉ được d\xf9ng để phản hồi y\xeau cầu n\xe0y.","success":"Cảm ơn bạn — ch\xfang t\xf4i đ\xe3 nhận được y\xeau cầu v\xe0 sẽ li\xean hệ sớm.","error":"Đ\xe3 c\xf3 lỗi khi gửi y\xeau cầu. Vui l\xf2ng thử lại hoặc gửi email trực tiếp cho ch\xfang t\xf4i."},"sidebar":{"direct":{"title":"Li\xean hệ trực tiếp"},"hours":"Thứ Hai – Thứ Bảy, 8:00 – 17:30 (GMT+7)","next":{"title":"C\xe1c bước tiếp theo","step1":"Ch\xfang t\xf4i xem x\xe9t th\xf4ng tin v\xe0 gọi hoặc nhắn tin cho bạn trong 1–2 ng\xe0y l\xe0m việc","step2":"Ch\xfang t\xf4i sắp xếp khảo s\xe1t thực tế miễn ph\xed để kiểm tra m\xe1i v\xe0 tải ti\xeau thụ","step3":"Bạn nhận được b\xe1o gi\xe1 chi tiết k\xe8m c\xf4ng suất hệ thống, thiết bị v\xe0 chi ph\xed"},"trust":"Đ\xe2y l\xe0 một cuộc trao đổi kh\xf4ng \xe1p lực. Ch\xfang t\xf4i sẽ n\xf3i thật nếu điện mặt trời chưa ph\xf9 hợp với t\xecnh h\xecnh của bạn."}},"privacy":{"title":"Ch\xednh s\xe1ch bảo mật","lastUpdated":"Cập nhật lần cuối: Th\xe1ng 6, 2026","intro":"Trang n\xe0y giải th\xedch th\xf4ng tin n\xe0o SolarTNP thu thập qua website, c\xe1ch ch\xfang t\xf4i sử dụng th\xf4ng tin đ\xf3, v\xe0 quyền của bạn đối với th\xf4ng tin n\xe0y.","s01":{"heading":"Th\xf4ng tin ch\xfang t\xf4i thu thập","body":"Khi bạn gửi biểu mẫu li\xean hệ, ch\xfang t\xf4i thu thập họ t\xean, email, số điện thoại (kh\xf4ng bắt buộc) v\xe0 th\xf4ng tin dự \xe1n (loại c\xf4ng tr\xecnh, vị tr\xed, diện t\xedch m\xe1i, h\xf3a đơn tiền điện h\xe0ng th\xe1ng, ghi ch\xfa dự \xe1n). Ch\xfang t\xf4i chỉ d\xf9ng th\xf4ng tin n\xe0y để phản hồi y\xeau cầu v\xe0 chuẩn bị b\xe1o gi\xe1. Ch\xfang t\xf4i kh\xf4ng tự động thu thập dữ liệu qua cookie, ngoại trừ một cookie chức năng duy nhất để ghi nhớ t\xf9y chọn ng\xf4n ngữ."},"s02":{"heading":"C\xe1ch ch\xfang t\xf4i sử dụng th\xf4ng tin của bạn","body":"Th\xf4ng tin li\xean hệ của bạn được d\xf9ng để phản hồi y\xeau cầu khảo s\xe1t, chuẩn bị v\xe0 gửi b\xe1o gi\xe1, v\xe0 theo d\xf5i nếu bạn chưa nhận được phản hồi. Ch\xfang t\xf4i kh\xf4ng d\xf9ng th\xf4ng tin của bạn cho mục đ\xedch quảng c\xe1o kh\xf4ng mong muốn. Ch\xfang t\xf4i kh\xf4ng b\xe1n, cho thu\xea hoặc chia sẻ th\xf4ng tin của bạn với b\xean thứ ba, trừ khi ph\xe1p luật y\xeau cầu."},"s03":{"heading":"Lưu trữ dữ liệu","body":"Biểu mẫu li\xean hệ được xử l\xfd qua Formspree (formspree.io), một dịch vụ biểu mẫu của b\xean thứ ba. Ch\xednh s\xe1ch bảo mật của Formspree \xe1p dụng cho dữ liệu xử l\xfd tr\xean nền tảng của họ. Ch\xfang t\xf4i lưu trữ th\xf4ng tin y\xeau cầu của bạn trong thời gian cần thiết để xử l\xfd y\xeau cầu hoặc theo quy định ph\xe1p luật Việt Nam."},"s04":{"heading":"Cookie","body":"Website n\xe0y chỉ d\xf9ng một cookie chức năng duy nhất để ghi nhớ t\xf9y chọn ng\xf4n ngữ hoặc th\xf4ng b\xe1o bảo mật của bạn. Kh\xf4ng sử dụng cookie theo d\xf5i, pixel quảng c\xe1o hoặc script ph\xe2n t\xedch. Ch\xfang t\xf4i kh\xf4ng sử dụng Google Analytics hay bất kỳ dịch vụ theo d\xf5i của b\xean thứ ba n\xe0o."},"s05":{"heading":"Quyền của bạn","body":"Bạn c\xf3 quyền truy cập, chỉnh sửa hoặc y\xeau cầu x\xf3a dữ liệu c\xe1 nh\xe2n của m\xecnh. Để thực hiện c\xe1c quyền n\xe0y, vui l\xf2ng gửi email tới thuy@tnpgr.vn. Ch\xfang t\xf4i sẽ phản hồi trong v\xf2ng 30 ng\xe0y."},"s06":{"heading":"Li\xean hệ với ch\xfang t\xf4i","body":"Với c\xe1c c\xe2u hỏi về bảo mật: thuy@tnpgr.vn \xb7 +84 90 333 37 29. L\xf4 35 đường số 9, KCN Tam Phước, Bi\xean H\xf2a, Việt Nam."},"backHome":"Về trang chủ"},"regulations":{"title":"Quy định điện mặt trời tại Việt Nam — Những điều cần biết","subtitle":"Nghị định 135/2024/NĐ-CP quản l\xfd điện mặt trời m\xe1i nh\xe0 tại Việt Nam. Ch\xfang t\xf4i đ\xe3 t\xf3m tắt những g\xec quy định n\xe0y c\xf3 nghĩa đối với c\xf4ng tr\xecnh của bạn — v\xe0 c\xe1ch SolarTNP xử l\xfd c\xe1c thủ tục tu\xe2n thủ cho bạn.","disclaimer":"Trang n\xe0y t\xf3m tắt hiểu biết của ch\xfang t\xf4i về Nghị định 135/2024/NĐ-CP t\xednh đến ng\xe0y b\xean dưới. Quy định về điện mặt trời tại Việt Nam c\xf3 thể thay đổi. Đ\xe2y kh\xf4ng phải l\xe0 tư vấn ph\xe1p l\xfd — h\xe3y tham khảo luật sư chuy\xean về năng lượng hoặc x\xe2y dựng để c\xf3 hướng dẫn ch\xednh thức.","s1":{"heading":"Quy tắc cốt l\xf5i: Tự d\xf9ng l\xe0 ch\xednh","body":"Theo Nghị định 135/2024/NĐ-CP, hệ thống điện mặt trời m\xe1i nh\xe0 tại Việt Nam phải được lắp đặt chủ yếu để tự sử dụng tại chỗ. C\xf4ng suất hệ thống n\xf3i chung phải ph\xf9 hợp với tải ti\xeau thụ điện hiện c\xf3 tại thời điểm đăng k\xfd. Đ\xe2y l\xe0 một ưu điểm, kh\xf4ng phải hạn chế — n\xf3 đảm bảo hệ thống được t\xednh to\xe1n đ\xfang theo nhu cầu thực tế, kh\xf4ng b\xe1n qu\xe1 c\xf4ng suất cần thiết."},"s2":{"heading":"B\xe1n điện dư l\xean lưới EVN (giới hạn 20%)","body":"Bạn được ph\xe9p b\xe1n điện dư cho Tập đo\xe0n Điện lực Việt Nam (EVN), nhưng bị giới hạn nghi\xeam ngặt ở mức 20% c\xf4ng suất lắp đặt. Điện dư b\xe1n cho EVN được thanh to\xe1n theo gi\xe1 thị trường điện b\xecnh qu\xe2n của năm trước — kh\xf4ng c\xf2n \xe1p dụng gi\xe1 FIT cao như trước. \xdd nghĩa thực tế: hiệu quả t\xe0i ch\xednh của điện mặt trời hiện nay chủ yếu đến từ tiết kiệm tiền điện tự d\xf9ng, kh\xf4ng phải từ doanh thu b\xe1n điện dư.","cap":"Điện dư b\xe1n tối đa cho EVN: 20% c\xf4ng suất lắp đặt"},"s3":{"heading":"Trường hợp ngoại lệ: Hệ thống độc lập (off-grid)","body":"Nếu hệ thống của bạn ho\xe0n to\xe0n kh\xf4ng kết nối với lưới điện quốc gia, sẽ kh\xf4ng c\xf3 giới hạn c\xf4ng suất. Điều n\xe0y \xe1p dụng cho c\xe1c c\xf4ng tr\xecnh ở v\xf9ng xa hoặc doanh nghiệp muốn tự chủ ho\xe0n to\xe0n về năng lượng với hệ thống lưu trữ pin."},"s4":{"heading":"Ngưỡng c\xf4ng suất & Cấp ph\xe9p","intro":"Tr\xecnh b\xe0y dưới dạng bảng so s\xe1nh r\xf5 r\xe0ng:","row1":{"range":"Dưới 100 kW","who":"Hộ gia đ\xecnh, doanh nghiệp nhỏ","process":"Th\xf4ng b\xe1o đơn giản tới Sở C\xf4ng Thương (DOIT) cấp tỉnh — kh\xf4ng cần ph\xea duyệt đầu tư"},"row2":{"range":"100 kW – 1.000 kW","who":"Doanh nghiệp / c\xf4ng nghiệp quy m\xf4 vừa","process":"Cấp ph\xe9p th\xf4ng thường với ch\xednh quyền địa phương"},"row3":{"range":"Tr\xean 1.000 kW (1 MW+)","who":"Doanh nghiệp / c\xf4ng nghiệp lớn b\xe1n điện l\xean lưới","process":"Cần giấy chứng nhận đăng k\xfd đầu tư v\xe0 Giấy ph\xe9p hoạt động điện lực"},"headers":{"capacity":"C\xf4ng suất","who":"Đối tượng","process":"Quy tr\xecnh"}},"s5":{"heading":"Y\xeau cầu tu\xe2n thủ về c\xf4ng tr\xecnh","body":"Hệ thống m\xe1i nh\xe0 phải được lắp tr\xean c\xf4ng tr\xecnh tu\xe2n thủ đầy đủ ph\xe1p luật x\xe2y dựng, quyền sử dụng đất, ti\xeau chuẩn ph\xf2ng ch\xe1y chữa ch\xe1y v\xe0 quy định m\xf4i trường. SolarTNP kiểm tra sự tu\xe2n thủ của c\xf4ng tr\xecnh trong buổi khảo s\xe1t trước khi lắp đặt — ch\xfang t\xf4i sẽ kh\xf4ng thi c\xf4ng tr\xean c\xf4ng tr\xecnh c\xf2n vướng vấn đề ph\xe1p l\xfd chưa giải quyết."},"s6":{"heading":"C\xe1ch SolarTNP xử l\xfd điều n\xe0y","items":["Ch\xfang t\xf4i t\xednh to\xe1n c\xf4ng suất hệ thống theo đ\xfang tải ti\xeau thụ thực tế — tu\xe2n thủ ngay từ thiết kế","Ch\xfang t\xf4i chuẩn bị v\xe0 nộp th\xf4ng b\xe1o DOIT (đối với hệ thống dưới 100 kW)","Ch\xfang t\xf4i phối hợp xin ph\xea duyệt h\xf2a lưới v\xe0 nghiệm thu với EVN","Ch\xfang t\xf4i ghi r\xf5 giới hạn 20% điện dư trong hồ sơ thiết kế hệ thống","Ch\xfang t\xf4i kh\xf4ng thi c\xf4ng tr\xean c\xf4ng tr\xecnh chưa tu\xe2n thủ quy định"]},"sources":{"label":"Nguồn tham khảo","note":"Nghị định 135/2024/NĐ-CP (văn bản ch\xednh thức) \xb7 SP Global Energy Transition (10/2024) \xb7 B\xe0i viết hướng dẫn WFW \xb7 Vietnam Business Law blog (01/2025, 03/2025) \xb7 Vietnam Law Magazine \xb7 Baker McKenzie InsightPlus","lastVerified":"X\xe1c minh lần cuối: 17 th\xe1ng 6, 2026"}},"notFound":{"fourofour":"404","tagline":"Trang n\xe0y đ\xe3... mất điện.","body":"Đường dẫn n\xe0y kh\xf4ng tồn tại. H\xe3y để ch\xfang t\xf4i đưa bạn về nơi c\xf3 nắng.","goHome":"Về trang chủ","contact":"Li\xean hệ"},"meta":{"home":{"title":"SolarTNP — Điện mặt trời chất lượng Nhật Bản tại Việt Nam","description":"SolarTNP thiết kế, cung cấp v\xe0 lắp đặt hệ thống điện mặt trời h\xf2a lưới nhập từ Nhật Bản tại Bi\xean H\xf2a, Đồng Nai v\xe0 miền Nam Việt Nam. C\xf4ng tr\xecnh thực tế, gi\xe1 cả minh bạch."},"pricing":{"title":"Bảng gi\xe1 & Thời gian ho\xe0n vốn điện mặt trời — SolarTNP","description":"Ba mức c\xf4ng suất, hạng mục r\xf5 r\xe0ng v\xe0 c\xe1i nh\xecn trung thực về thời gian ho\xe0n vốn điện mặt trời tại Việt Nam. Phần hỏi đ\xe1p theo đ\xfang Nghị định 135/2024/NĐ-CP."},"contact":{"title":"Đăng k\xfd khảo s\xe1t miễn ph\xed — SolarTNP","description":"Li\xean hệ SolarTNP để khảo s\xe1t điện mặt trời miễn ph\xed tại Bi\xean H\xf2a, TP. Hồ Ch\xed Minh hoặc miền Nam Việt Nam. B\xe1o gi\xe1 kh\xf4ng \xe1p lực dựa tr\xean m\xe1i nh\xe0 v\xe0 h\xf3a đơn tiền điện của bạn."},"privacy":{"title":"Ch\xednh s\xe1ch bảo mật — SolarTNP","description":"C\xe1ch SolarTNP thu thập, sử dụng v\xe0 bảo vệ th\xf4ng tin của bạn khi li\xean hệ để khảo s\xe1t điện mặt trời."},"regulations":{"title":"Giải th\xedch quy định điện mặt trời Việt Nam — SolarTNP","description":"Hướng dẫn dễ hiểu về Nghị định 135/2024/NĐ-CP — quy tắc tự d\xf9ng, giới hạn 20% điện dư b\xe1n cho EVN v\xe0 ngưỡng cấp ph\xe9p cho điện mặt trời m\xe1i nh\xe0 tại Việt Nam."}}}')}};